!function(){"use strict";window.StringUtils={createPacPlugin:()=>({name:"StringUtils",functions:{capitalize:e=>e.charAt(0).toUpperCase()+e.slice(1).toLowerCase(),upper:e=>e.toUpperCase(),lower:e=>e.toLowerCase(),trim:e=>e.trim(),truncate:(e,t,r="…")=>e.length<=t?e:e.slice(0,t-r.length)+r,replace:(e,t,r)=>e.replace(t,r),replaceAll:(e,t,r)=>e.replaceAll(t,r),startsWith:(e,t)=>e.startsWith(t),endsWith:(e,t)=>e.endsWith(t),contains:(e,t)=>e.includes(t),padStart:(e,t,r=" ")=>e.padStart(t,r),padEnd:(e,t,r=" ")=>e.padEnd(t,r),repeat:(e,t)=>e.repeat(t),length:e=>e.length,slug:e=>e.toLowerCase().trim().replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,""),countStr:(e,t)=>{if(!e)return 0;let r=0,s=0;for(;-1!==(s=t.indexOf(e,s));)r++,s+=e.length;return r},containsText:(e,t)=>e.toLowerCase().includes(t.toLowerCase()),startsText:(e,t)=>e.toLowerCase().startsWith(t.toLowerCase()),endsText:(e,t)=>e.toLowerCase().endsWith(t.toLowerCase()),reverseString:e=>e.split("").reverse().join("")},onComponentCreated(e,t,r){const s=r.stringUtils?.property;s&&s in e&&(e[s]=this.functions)}})}}();